import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Branch SDK Overview","description":"","frontmatter":{"title":"Branch SDK Overview","slug":"native-sdks-overview"},"headers":[],"relativePath":"developer-hub/native-sdks-overview.md","filePath":"developer-hub/native-sdks-overview.md"}'),i={name:"developer-hub/native-sdks-overview.md"};function n(s,e,p,l,d,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="what-is-the-branch-sdk" tabindex="-1">What is the Branch SDK? <a class="header-anchor" href="#what-is-the-branch-sdk" aria-label="Permalink to &quot;What is the Branch SDK?&quot;">​</a></h2><p>The Branch SDK is a comprehensive mobile linking platform that enables developers to create and manage deep links for seamless user experiences across devices, platforms, and channels. With the Branch SDK, you can implement deferred deep linking, contextual deep linking, and attribution tracking to drive user acquisition, engagement, and retention.</p><p>Whether you&#39;re building features for user onboarding, referral programs, content sharing, or marketing campaigns, the Branch SDK provides the tools to create intelligent links that route users to the right content at the right time, even if they need to install your app first.</p><h2 id="native-sdks" tabindex="-1">Native SDKs <a class="header-anchor" href="#native-sdks" aria-label="Permalink to &quot;Native SDKs&quot;">​</a></h2><p>Branch offers native SDKs for all major mobile and desktop platforms, allowing you to integrate deep linking capabilities directly into your applications with platform-specific APIs and best practices.</p><h3 id="mobile-platforms" tabindex="-1">Mobile platforms <a class="header-anchor" href="#mobile-platforms" aria-label="Permalink to &quot;Mobile platforms&quot;">​</a></h3><p><strong>Android SDK</strong> - Full-featured SDK for Android applications, supporting Android Instant Apps and providing seamless deep linking experiences for Android users.</p><p><strong>iOS SDK</strong> - Comprehensive SDK for iOS applications, with support for iMessage Apps and native iOS features to maximize engagement on Apple devices.</p><h3 id="desktop-and-other-platforms" tabindex="-1">Desktop and other platforms <a class="header-anchor" href="#desktop-and-other-platforms" aria-label="Permalink to &quot;Desktop and other platforms&quot;">​</a></h3><p><strong>Web SDK</strong> - JavaScript SDK for web applications, enabling deep linking from websites and web apps.</p><p><strong>macOS SDK</strong> - Native SDK for macOS desktop applications.</p><p><strong>Windows SDK</strong> - SDK for Windows desktop applications built with C++.</p><p><strong>tvOS SDK</strong> - SDK for Apple TV applications, bringing deep linking to the living room.</p><p><strong>Roku SDK</strong> - SDK for Roku streaming applications.</p><h2 id="beyond-native-sdks" tabindex="-1">Beyond native SDKs <a class="header-anchor" href="#beyond-native-sdks" aria-label="Permalink to &quot;Beyond native SDKs&quot;">​</a></h2><p>In addition to our native SDKs, Branch also provides plugins and wrappers for popular cross-platform frameworks and game engines, making it easy to integrate Branch regardless of your development stack. These include support for React Native, Flutter, Unity, Cordova, and more.</p><h2 id="open-source" tabindex="-1">Open source <a class="header-anchor" href="#open-source" aria-label="Permalink to &quot;Open source&quot;">​</a></h2><p>All Branch SDKs are open source and available on GitHub. You can view the source code, contribute to development, report issues, and stay up-to-date with the latest releases at our GitHub organization: <a href="https://www.github.com/branchmetrics" target="_blank" rel="noreferrer">github.com/branchmetrics</a></p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p>Explore the documentation for your specific platform to get started with integration, or check out the <a href="./sdk-integration-tracker.html">SDK Integration Tracker</a> within Branch to monitor your implementation progress.</p><h4 id="platform-links" tabindex="-1">Platform links <a class="header-anchor" href="#platform-links" aria-label="Permalink to &quot;Platform links&quot;">​</a></h4><p><a href="./android-sdk-overview.html">Android SDK</a></p><p><a href="./ios-sdk-overview.html">iOS SDK</a></p><p><a href="./web-sdk-overview.html">Web SDK</a></p><p><a href="./macos-sdk-overview.html">macOS SDK</a></p><p><a href="./windows-cpp-sdk-overview.html">Windows C++ SDK</a></p><p><a href="./tvos-sdk-overview.html">tvOS SDK</a></p><p><a href="./roku-sdk-overview.html">Roku SDK</a></p>',28)])])}const u=a(i,[["render",n]]);export{m as __pageData,u as default};
